import android.app.Activity;
import android.content.Context;
import android.os.Bundle;
import android.util.Log;
import android.view.View;
import android.widget.Button;
import android.widget.TextView;

public class BankingApp extends Activity {

    private static final String TAG = "BankingApp";
    private TextView balanceTextView;
    private Button depositButton;
    private Button withdrawButton;
    private Account account;

    @Override
    protected void onCreate(Bundle savedInstanceState) {
        super.onCreate(savedInstanceState);
        setContentView(R.layout.activity_main);

        // Initialize UI components
        balanceTextView = findViewById(R.id.balance_text_view);
        depositButton = findViewById(R.id.deposit_button);
        withdrawButton = findViewById(R.id.withdraw_button);

        // Initialize account object
        account = new Account(1000.0); // Initial balance

        // Set up button listeners
        depositButton.setOnClickListener(new View.OnClickListener() {
            @Override
            public void onClick(View v) {
                deposit();
            }
        });

        withdrawButton.setOnClickListener(new View.OnClickListener() {
            @Override
            public void onClick(View v) {
                withdraw();
            }
        });
    }

    private void deposit() {
        // Simulate deposit operation
        double amount = 100.0;
        account.deposit(amount);
        balanceTextView.setText(String.valueOf(account.getBalance()));
    }

    private void withdraw() {
        // Simulate withdrawal operation
        double amount = 50.0;
        if (account.withdraw(amount)) {
            balanceTextView.setText(String.valueOf(account.getBalance()));
        } else {
            Log.e(TAG, "Insufficient funds");
        }
    }

    public class Account {
        private double balance;

        public Account(double initialBalance) {
            this.balance = initialBalance;
        }

        public void deposit(double amount) {
            balance += amount;
        }

        public boolean withdraw(double amount) {
            if (balance >= amount) {
                balance -= amount;
                return true;
            }
            return false;
        }

        public double getBalance() {
            return balance;
        }
    }

    // Device integrity checks
    private boolean isDeviceIntact(Context context) {
        // Simple implementation for demonstration purposes
        // In a real-world scenario, use a more robust library like Frida or Checkra1n
        String deviceInfo = android.os.Build.MODEL + " " + android.os.Build.VERSION.RELEASE;
        return !deviceInfo.contains("root") && !deviceInfo.contains("jailbreak");
    }

    private void checkDeviceIntegrity() {
        if (!isDeviceIntact(this)) {
            // Gate sensitive features behind additional protections
            depositButton.setEnabled(false);
            withdrawButton.setEnabled(false);
            Log.e(TAG, "Device integrity compromised. Sensitive features disabled.");
        }
    }
}